    AVRational input_time_base = inputFormatContext->streams[input_stream_index]->time_base;
    AVRational output_time_base = outputFormatContext->streams[input_stream_index]->time_base;

    if (input_stream_index == videoStreamIndex || input_stream_index == audioStreamIndex) {
        // Modify input PTS first
        if (packet.pts < packet.dts) {
            packet.pts = packet.dts;
        }

        // Modify input DTS
